const crypto = require('crypto');
const webhookBody = $('Webhook Trigger').first().json.body;
const headers = $('Webhook Trigger').first().json.headers;
const secret = $('Workflow Constants').first().json.N8N_SHARED_SECRET;

const signature = headers['x-profunda-signature'];
if (!signature) throw new Error('Missing x-profunda-signature header');
if (!webhookBody || typeof webhookBody !== 'object') throw new Error('Missing or invalid webhook body');
if (webhookBody.workflow_key !== 'watchlist_diff') throw new Error('workflow_key must be watchlist_diff');
if (!webhookBody.run_id) throw new Error('Missing run_id');

const bodyStr = JSON.stringify(webhookBody);
const hmac = crypto.createHmac('sha256', secret).update(bodyStr).digest('hex');
if (hmac !== signature) throw new Error('Invalid HMAC signature');

return [{ json: webhookBody }];

const input = $('Verify Signature').first().json;
const UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;

if (!input.org_id || typeof input.org_id !== 'string' || !UUID_RE.test(input.org_id)) {
  throw new Error('org_id must be a valid UUID');
}

let website_url = input.website_url || null;
if (website_url && typeof website_url === 'string') {
  website_url = website_url.trim();
  if (!/^https?:\/\//i.test(website_url)) website_url = 'https://' + website_url;
}

return [{
  json: {
    run_id: input.run_id,
    workflow_key: 'watchlist_diff',
    org_id: input.org_id,
    org_name: input.org_name || null,
    website_url
  }
}];

const validated = $('Validate Input').first().json;
const url = validated.website_url;

if (!url) {
  return [{ json: { run_id: validated.run_id, org_id: validated.org_id, crawl_skipped: true, skip_reason: 'No website URL' } }];
}

let prevHash = null;
try {
  const prev = $('Fetch Previous Snapshot').first().json;
  if (Array.isArray(prev) && prev.length > 0) prevHash = prev[0].content_hash;
  else if (prev && prev.content_hash) prevHash = prev.content_hash;
} catch(e) {}

return [{ json: { run_id: validated.run_id, org_id: validated.org_id, org_name: validated.org_name, website_url: url, previous_hash: prevHash, crawl_skipped: false } }];

const ctx = $('Resolve Context').first().json;
const crypto = require('crypto');

if (ctx.crawl_skipped) {
  return [{ json: { run_id: ctx.run_id, org_id: ctx.org_id, changed: false, content_hash: null, diff_signals: [], crawl_skipped: true } }];
}

let scrapeData;
try { scrapeData = $('Firecrawl Scrape').first().json; } catch(e) {
  return [{ json: { run_id: ctx.run_id, org_id: ctx.org_id, changed: false, content_hash: null, diff_signals: [], crawl_error: String(e.message).slice(0, 200) } }];
}

if (scrapeData.error || !scrapeData.success) {
  return [{ json: { run_id: ctx.run_id, org_id: ctx.org_id, changed: false, content_hash: null, diff_signals: [], crawl_error: scrapeData.error || 'Unsuccessful' } }];
}

const markdown = scrapeData.data?.markdown || '';
const newHash = crypto.createHash('sha256').update(markdown).digest('hex');
const changed = ctx.previous_hash ? (newHash !== ctx.previous_hash) : true;

const diff_signals = [];
if (changed) {
  diff_signals.push({ signal_type: 'content_changed', summary: 'Website content has been updated', confidence: 0.9 });

  // Detect specific changes
  const lower = markdown.toLowerCase();
  if (lower.includes('new') || lower.includes('announcement')) diff_signals.push({ signal_type: 'announcement', summary: 'Potential new announcement detected', confidence: 0.6 });
  if (lower.includes('hiring') || lower.includes('careers')) diff_signals.push({ signal_type: 'hiring', summary: 'Hiring-related content detected', confidence: 0.7 });
}

return [{ json: { run_id: ctx.run_id, org_id: ctx.org_id, changed, content_hash: newHash, diff_signals, crawl_error: null } }];

const validated = $('Validate Input').first().json;
let data = null;
let error = null;
let failed_node = null;

try { data = $('Compute Diff').first().json; } catch (e1) {
  try { data = $('Skip Crawl').first().json; } catch (e2) {
    error = 'No output';
    failed_node = 'Compute Diff';
  }
}

if (data && data.crawl_error) { error = data.crawl_error; failed_node = 'Firecrawl Scrape'; }

let result = null;
if (!error && data) {
  result = { org_id: data.org_id, changed: data.changed, content_hash: data.content_hash, diff_signals: data.diff_signals || [], crawl_skipped: data.crawl_skipped || false };
}

return [{ json: { run_id: validated.run_id, workflow_key: 'watchlist_diff', payload: { result, error, failed_node } } }];
